/**
 * If the allocate flow throws RuntimeException (the ACME-not-
 * implemented case from TlsCertificateManager bleeding up through
 * an alternate code path), the controller must return 501 Not
 * Implemented with the stable error code. We exercise this by
 * having DnsAliasManager throw a RuntimeException for a missing
 * server (simulating the upstream throw) — the controller's
 * catch(\RuntimeException) clause is what we are asserting on.
 */
public function test_allocate_returns_501_when_runtime_exception_bubbles_up(): void
{
    $dnsManager = $this->createMock(DnsAliasManager::class);
    $dnsManager->method('allocateSubdomain')->willThrowException(new \RuntimeException(
        'ACME certificate provisioning is not implemented in this build. '
        . 'Provision certs out-of-band — see docs/hub-admin/tls.md.',
    ));

    $certManager = $this->createMock(TlsCertificateManager::class);
    $jwtService = $this->createMock(EnrollmentJwtService::class);
    $jwtService->method('validateEnrollmentJwt')->willReturn([
        'server_id' => 'server-123',
    ]);

    $controller = new SubdomainController($dnsManager, $certManager, $jwtService);

    // Build a JWT with a recognisable kid header so extractKid() succeeds.
    $header = rtrim(strtr(base64_encode((string) json_encode(['kid' => 'test-kid'])), '+/', '-_'), '=');
    $body = rtrim(strtr(base64_encode((string) json_encode(['server_id' => 'server-123'])), '+/', '-_'), '=');
    $token = $header . '.' . $body . '.sig';

    $request = $this->createRequest('POST', [], 'Bearer ' . $token);
    $response = $controller->allocate($request, ['id' => 'server-123']);

    $this->assertSame(501, $response->statusCode);
    $body = (string) $response->body;
    $this->assertStringContainsString('NOT_IMPLEMENTED', $body);
    $this->assertStringContainsString('tls.acme_not_implemented', $body);
    $this->assertStringContainsString('docs/hub-admin/tls.md', $body);
}

